#include <iostream>
#include <vector>
#include <memory>

class Counter {
public:
    static int s_count;

    Counter() {
        s_count++;
    }

    ~Counter() {
        s_count--;
    }

    static int getTotalCount() {
        return s_count;
    }
};

int Counter::s_count = 0;

int main() {
    std::cout << "--- Initial state ---" << std::endl;
    std::cout << "Current active counters: " << Counter::getTotalCount() << std::endl;

    std::cout << "\n--- Creating first batch of counters ---" << std::endl;
    Counter c1;
    {
        Counter c2;
        std::cout << "Inside scope (c1, c2 active). Current active counters: " << Counter::getTotalCount() << std::endl;
    }
    std::cout << "After scope (c1 active). Current active counters: " << Counter::getTotalCount() << std::endl;

    std::vector<Counter> counters_vec(3);
    std::cout << "After vector creation (c1, 3 in vec active). Current active counters: " << Counter::getTotalCount() << std::endl;

    std::cout << "\n--- Introducing a robustness issue: directly modifying s_count ---" << std::endl;
    Counter::s_count = -5;
    std::cout << "Counter::s_count manually set to -5. Current active counters: " << Counter::getTotalCount() << std::endl;

    std::cout << "\n--- Creating more counters after corruption ---" << std::endl;
    Counter c3;
    Counter* c4 = new Counter();
    std::cout << "After creating c3, c4 (c1, 3 in vec, c3, c4 active, but s_count corrupted). Current active counters: " << Counter::getTotalCount() << std::endl;

    delete c4;
    std::cout << "After deleting c4. Current active counters: " << Counter::getTotalCount() << std::endl;

    std::cout << "\n--- End of main function ---" << std::endl;
    return 0;
}
